export interface User {
  id: string;
  email: string;
  passwordHash: string;
  /**
   * Timestamp of the last password change.
   * Used to invalidate sessions created before this time.
   */
  lastPasswordChangeAt: Date;
}

export interface PasswordResetToken {
  token: string;
  userId: string;
  expiresAt: Date;
  used: boolean;
}

// For this exercise, we'll use `lastPasswordChangeAt` on the User
// to invalidate sessions, so a full Session object isn't strictly needed
// for the *invalidation* part, but it's good to define for completeness.
export interface Session {
  id: string;
  userId: string;
  createdAt: Date;
  expiresAt: Date;
}
