import { User, PasswordResetToken, Session } from './types';

/**
 * In-memory "database" for demonstration purposes.
 * In a real application, these would be database models and queries.
 */
export const users = new Map<string, User>();
export const passwordResetTokens = new Map<string, PasswordResetToken>();
export const sessions = new Map<string, Session>(); // Not directly used for invalidation in this specific feature, but good to have.

// Seed some initial data for testing
const testUserId = 'user-123';
const testUserEmail = 'test@example.com';
const initialPasswordHash = '$2b$10$e.g.a.hash.for.initial.password'; // Placeholder, will be updated
const initialLastPasswordChangeAt = new Date(Date.now() - 3600 * 1000); // 1 hour ago

users.set(testUserId, {
  id: testUserId,
  email: testUserEmail,
  passwordHash: initialPasswordHash,
  lastPasswordChangeAt: initialLastPasswordChangeAt,
});

// Example of a valid token for the test user
const validToken = 'valid-reset-token-123';
passwordResetTokens.set(validToken, {
  token: validToken,
  userId: testUserId,
  expiresAt: new Date(Date.now() + 3600 * 1000), // Expires in 1 hour
  used: false,
});

// Example of an expired token
const expiredToken = 'expired-reset-token-456';
passwordResetTokens.set(expiredToken, {
  token: expiredToken,
  userId: testUserId,
  expiresAt: new Date(Date.now() - 3600 * 1000), // Expired 1 hour ago
  used: false,
});

// Example of an already used token
const usedToken = 'used-reset-token-789';
passwordResetTokens.set(usedToken, {
  token: usedToken,
  userId: testUserId,
  expiresAt: new Date(Date.now() + 3600 * 1000), // Expires in 1 hour
  used: true,
});

console.log('DB seeded with test user and tokens.');
