```aether:src/routes/passwordResetConfirm.ts
import { Hono } from 'hono';
import { z } from 'zod';
import { zValidator } from '@hono/zod-validator';
import { users, passwordResetTokens } from '../db';
import { hashPassword } from '../utils/auth';

const passwordResetConfirmSchema = z.object({
  token: z.string().min(1, 'Token is required.'),
  newPassword: z.string().min(8, 'New password must be at least 8 characters long.'),
});

export const passwordResetConfirmRoute = new Hono();

passwordResetConfirmRoute.post(
  '/password-reset-confirm',
  zValidator('json', passwordResetConfirmSchema, (result, c) => {
    if (!result.success) {
      return c.json({ error: 'Invalid request body.', details: result.error.errors }, 400);
    }
  }),
  async (c) => {
    const { token, newPassword } = c.req.valid('json');

    // 1. Find the password reset token
    const resetToken = passwordResetTokens.get(token);

    if (!resetToken) {
      return c.json({ error: 'Invalid or expired token.' }, 400);
    }

    // 2. Check if the token is expired or already used
    if (resetToken.expiresAt < new Date() || resetToken.used) {
      // For security, we might return the same generic error message
      // as for an invalid token to prevent enumeration attacks.
      return c.json({ error: 'Invalid or expired token.' }, 400);
    }

    // 3. Find the user associated with the token
    const user = users.get(resetToken.userId);

    if (!user) {
      // This should ideally not happen if the token is valid and points to a real user.
      // Mark token as used to prevent further attempts if user somehow disappeared.
      resetToken.used = true;
      return c.json({ error: 'User not found for this token.' }, 404);
    }

    try {
      // 4. Hash the new password
      const newPasswordHash = await hashPassword(newPassword);

      // 5. Update the user's password
      user.passwordHash = newPasswordHash;

      // 6. Invalidate all existing sessions for the user
      // This is done by updating `lastPasswordChangeAt`.
      // Any session created before this timestamp is considered invalid.
      user.lastPasswordChangeAt = new Date();

      // 7. Mark the password reset token as used
      resetToken.used = true;

      // In a real application, you might also want to:
      // - Send a "password changed" notification email to the user.
      // - Log the event.

      return c.json({ message: 'Password has been successfully reset.' }, 200);
    } catch (error) {
      console.error('Error during password reset confirmation:', error);
      return c.json({ error: 'An internal server error occurred.' }, 500);
    }
  }
);
