import { Hono } from 'hono';
import { passwordResetConfirmRoute } from './routes/passwordResetConfirm';
import './db'; // Initialize the in-memory database

const app = new Hono();

// Register the password reset confirmation route
app.route('/', passwordResetConfirmRoute);

// Basic health check route
app.get('/', (c) => {
  return c.text('Aether Password Reset Service is running!');
});

// Error handling middleware (optional, but good practice)
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ error: 'An unexpected error occurred.' }, 500);
});

const port = 3000;
console.log(`Server is running on http://localhost:${port}`);

export default {
  port,
  fetch: app.fetch,
};
